    "= Vec::new(); numbers.push(10); numbers.push(20); numbers.pop();\" }, { category: \"Result і Option\", title: \"Option\", description: \"Option описує значення, яке може існувати або бути відсутнім.\", points: [\"Some(value) означає наявність значення\", \"None означає відсутність\", \"Краще обробляти через match або if let\"], code: \"let value: Option": "= Vec::baru(); angka.push(10); angka.push(20); angka.pop();\" }, { kategori: \"Hasil dan Opsi\", judul: \"Opsi\", deskripsi: \"Opsi menggambarkan suatu nilai yang mungkin ada atau tidak ada.\", poin: [\"Beberapa(nilai) berarti adanya nilai\", \"Tidak ada berarti tidak ada\", \"Lebih baik ditangani melalui pencocokan atau jika dibiarkan\"], kode: \"biarkan nilai: Opsi",
    "println!(\"Інше\"), }\" }, { category: \"Цикли\", title: \"loop\", description: \"loop створює нескінченний цикл, який зупиняють через break.\", points: [\"Підходить для повторення до явної зупинки\", \"break може повернути значення\"], code: \"let mut count = 0; loop { count += 1; if count == 3 { break; } }\" }, { category: \"Цикли\", title: \"while і for\", description: \"while працює поки умова true, for перебирає діапазони або колекції.\", points: [\"while зручний для умовного повторення\", \"for безпечний для перебору елементів\", \"0..5 створює діапазон від 0 до 4\"], code: \"let mut x = 0; while x": "println!(\"Lainnya\"), }\" }, { kategori: \"Perulangan\", judul: \"perulangan\", deskripsi: \"perulangan membuat perulangan tak terhingga yang dihentikan oleh break.\", poin: [\"Cocok untuk mengulang hingga berhenti secara eksplisit\", \"break dapat mengembalikan nilai\"], kode: \"biarkan mut count = 0; putaran { hitungan += 1; jika dihitung == 3 { putus; } }\" }, { kategori: \"Perulangan\", judul: \"sementara dan untuk\", deskripsi: \"sementara berfungsi selama kondisinya benar, untuk melakukan iterasi pada rentang atau koleksi.\", poin: [\"sementara nyaman untuk iterasi bersyarat\", \"for aman untuk elemen iterasi\", \"0..5 membuat rentang dari 0 hingga 4\"], kode: \"biarkan mut x = 0; sementara x",
    "println!(\"other\"), }\", note: \"match має покривати всі можливі випадки.\" }, { name: \"loop\", description: \"Створює нескінченний цикл.\", syntax: \"loop { }\", example: \"loop { break; }\", note: \"Потрібен break, якщо цикл має завершитись.\" }, { name: \"while\", description: \"Повторює код, поки умова true.\", syntax: \"while condition { }\", example: \"while x": "println!(\"other\"), }\", catatan: \"kecocokan harus mencakup semua kemungkinan kasus.\" }, { nama: \"loop\", deskripsi: \"Membuat loop tak terbatas.\", sintaksis: \"loop { }\", contoh: \"loop { break; }\", catatan: \"Istirahat diperlukan jika perulangan ingin dihentikan.\" }, { nama: \"sementara\", deskripsi: \"Mengulangi kode hingga kondisi benar.\", sintaksis: \"kondisi sementara { }\", contoh: \"sementara x",
    "i32 { a * b }\" }, { category: \"Власність\", title: \"Ownership\", description: \"Ownership визначає, хто володіє значенням у пам’яті.\", points: [\"У кожного значення є власник\", \"Коли власник виходить з області видимості, значення очищається\", \"Це дозволяє Rust працювати без garbage collector\"], code: \"let text = String::from(\"hello\"); let other = text; // text більше не можна використовувати, бо ownership перемістився\" }, { category: \"Власність\", title: \"Move і borrow\", description: \"Move передає власність, borrow дає тимчасове посилання без передачі власності.\", points: [\"Move часто стається з String, Vec та іншими heap-типами\", \"& створює незмінну позику\", \"&mut створює змінну позику\"], code: \"fn print_len(text: &String) { println!(\"{}\", text.len()); } let name = String::from(\"Rust\"); print_len(&name); println!(\"{}\", name);\" }, { category: \"Позики\", title: \"& і &mut\", description: \"Посилання дозволяють працювати зі значенням без копіювання.\", points: [\"&T дає читання\", \"&mut T дозволяє змінювати\", \"Одночасно може бути або багато &T, або одне &mut T\"], code: \"fn add_word(text: &mut String) { text.push_str(\" language\"); } let mut title = String::from(\"Rust\"); add_word(&mut title);\" }, { category: \"Lifetimes\", title: \"Життєвий цикл\", description: \"Lifetime показує, як довго посилання залишається дійсним.\", points: [\"У більшості простих випадків компілятор виводить lifetimes сам\", \"Позначення 'a використовується, коли треба явно пов’язати посилання\", \"Lifetimes не продовжують життя даних, а лише описують його\"], code: \"fn longest": "i32 { a * b }\" }, { kategori: \"Kepemilikan\", judul: \"Kepemilikan\", deskripsi: \"Kepemilikan menentukan siapa yang memiliki suatu nilai dalam memori.\", poin: [\"Setiap nilai mempunyai pemilik\", \"Ketika pemilik keluar dari cakupan, nilainya dihapus\", \"Ini memungkinkan Rust berjalan tanpa pengumpul sampah\"], kode: \"let text = String::from(\"hello\"); biarkan lainnya = teks; // teks tidak dapat digunakan lagi karena kepemilikan telah berpindah\" }, { kategori: \"Kepemilikan\", judul: \"Pindahkan dan pinjam\", deskripsi: \"Pindahan memindahkan kepemilikan, pinjam memberikan referensi sementara tanpa memindahkan kepemilikan.\", poin: [\"Pemindahan sering terjadi pada String, Vec, dan tipe heap lainnya\", \"& membuat peminjaman yang tidak dapat diubah\", \"&mut membuat peminjaman yang dapat diubah\"], kode: \"fn print_len(teks: &String) { println!(\"{}\", teks.len()); } biarkan nama = String::from(\"Karat\"); print_len(&nama); println!(\"{}\", nama);\" }, { kategori: \"Pinjaman\", judul: \"& dan &mut\", deskripsi: \"Referensi memungkinkan Anda bekerja dengan nilai tanpa menyalin.\", poin: [\"&T memberikan pembacaan\", \"&mut T memungkinkan perubahan\", \"Bisa ada banyak &T atau satu &mut T pada saat yang sama\"], kode: \"fn add_word(teks: &mut String) { text.push_str(\" bahasa\"); } biarkan mut title = String::from(\"Rust\"); add_word(&mut title);\" }, { kategori: \"Seumur Hidup\", judul: \"Seumur Hidup\", deskripsi: \"Seumur hidup menunjukkan berapa lama suatu referensi tetap valid.\", poin: [\"Dalam sebagian besar kasus sederhana, kompiler mengeluarkan masa hidup itu sendiri\", \"Notasi 'a' digunakan ketika Anda perlu mengikat referensi secara eksplisit\", \"Masa hidup tidak memperpanjang umur data, mereka hanya mendeskripsikannya\"], kode: \"fn terpanjang",
